content.problemStatement:
&nbsp;

The citizens of Byteland regularly play a game. They have blocks each denoting some integer from 0 to 9. These are arranged together in a random manner without seeing to form different numbers keeping in mind that the first block is never a 0. Once they form a number they read in the reverse order to check if the number and its reverse is the same. If both are same then the player wins. We call such numbers palindrome. 

Ash happens to see this game and wants to simulate the same in the computer. As the first step he wants to take an input from the user and check if the number is a palindrome and declare if the user wins or not.&nbsp;

code.C:
#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        char s[25];
        scanf("%s", s);
        int len=0; while(s[len]!='\0') len++;
        int i=0, j=len-1; int ok=1;
        while(i<j){
            if(s[i]!=s[j]){ ok=0; break; }
            i++; j--;
        }
        printf("%s\n", ok?"wins":"loses");
    }
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        string s; cin>>s;
        string rev=s; reverse(rev.begin(), rev.end());
        cout << (s==rev?"wins":"loses") << '\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for(int t=0; t<T; t++){
            String s = br.readLine().trim();
            String rev = new StringBuilder(s).reverse().toString();
            sb.append(s.equals(rev) ? "wins" : "loses");
            if(t!=T-1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

